write_mode = metadata['runtime_config']['write_mode']

for table in metadata['tables']:
    source_table = table['mapping_details'].split('.')[1].split(' ')[0]
    source_alias = table['target_alias']
    target_table = table['target_table']
    
    df = spark.read.format(read_format)
    if read_format == 'csv':
        df = df.option("header", "true").option("inferSchema", "true")
    df = df.load(f"{base_path}{source_table}.{read_format}").alias(source_alias)

    transformations = [col['transformation'].split('= ')[1] + f" as {col['target_column']}" 
                       for col in metadata['columns'] if col['target_table'] == source_alias]
    
    df = df.selectExpr(*transformations)
    
    write_df = df.write.mode(write_mode).format(write_format)
    if write_format == 'csv':
        write_df = write_df.option("header", "true")
    write_df.save(f"{target_path}{target_table}.{write_format}")

